teMutability":"view","type":"function"},{"inputs":[],"name":"proxyAdmin","outputs":[{"internalType":"contract IProxyAdmin","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[],"name":"proxyAdminOwner","outputs":[{"internalType":"address","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[],"name":"receiveLiquidity","outputs":[],"stateMutability":"payable","type":"function"},{"inputs":[],"name":"superchainConfig","outputs":[{"internalType":"contract ISuperchainConfig","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[],"name":"systemConfig","outputs":[{"internalType":"contract ISystemConfig","name":"","type":"address"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"_value","type":"uint256"}],"name":"unlockETH","outputs":[],"stateMutability":"nonpayable","type":"function"},{"inputs":[],"name":"version","outputs":[{"internalType":"string","name":"","type":"string"}],"stateMutability":"view","type":"function"}],"devdoc":{"custom:proxied":"true","events":{"ETHLocked(address,uint256)":{"params":{"amount":"The amount of ETH locked.","portal":"The address of the portal that locked the ETH."}},"ETHUnlocked(address,uint256)":{"params":{"amount":"The amount of ETH unlocked.","portal":"The address of the portal that unlocked the ETH."}},"LiquidityMigrated(address,uint256)":{"params":{"lockbox":"The address of the ETH lockbox that was migrated."}},"LiquidityReceived(address,uint256)":{"params":{"amount":"The amount of ETH received.","lockbox":"The address of the ETH lockbox that received the liquidity."}},"LockboxAuthorized(address)":{"params":{"lockbox":"The address of the ETH lockbox that was authorized."}},"PortalAuthorized(address)":{"params":{"portal":"The address of the portal that was authorized."}}},"kind":"dev","methods":{"authorizeLockbox(address)":{"params":{"_lockbox":"The address of the ETH lockbox to authorize."}},"authorizePortal(address)":{"params":{"_portal":"The address of the portal to authorize."}},"initVersion()":{"returns":{"_0":"The current initialization version."}},"initialize(address,address[])":{"details":"Note: Multiple chains can share an ETHLockbox contract. In this case, all SystemConfig      contracts will point to the same pause identifier (the lockbox itself). Therefore, it      doesn't matter which SystemConfig is used here as long as it belongs to one of the      chains that share the lockbox.","params":{"_portals":"The addresses of the portals to authorize.","_systemConfig":"The address of the SystemConfig contract."}},"migrateLiquidity(address)":{"details":"Must be called atomically with `OptimismPortal.migrateToSuperRoots()` in the same         transaction batch, or otherwise the OptimismPortal may not be able to unlock ETH         from the ETHLockbox on finalized withdrawals.","params":{"_lockbox":"The address of the ETH lockbox to migrate liquidity to."}},"superchainConfig()":{"returns":{"_0":"ISuperchainConfig The SuperchainConfig contract."}},"unlockETH(uint256)":{"params":{"_value":"The amount of ETH to unlock."}},"version()":{"custom:semver":"1.2.0"}},"title":"ETHLockbox","version":1},"userdoc":{"errors":{"ETHLockbox_DifferentSuperchainConfig()":[{"notice":"Thrown when any authorized portal has a different SuperchainConfig."}],"ETHLockbox_InsufficientBalance()":[{"notice":"Thrown when the value to unlock is greater than the balance of the lockbox."}],"ETHLockbox_NoWithdrawalTransactions()":[{"notice":"Thrown when attempting to unlock ETH from the lockbox through a withdrawal transaction."}],"ETHLockbox_Paused()":[{"notice":"Thrown when the lockbox is paused."}],"ETHLockbox_Unauthorized()":[{"notice":"Thrown when the caller is not authorized."}],"ProxyAdminOwnedBase_NotProxyAdmin()":[{"notice":"Thrown when the caller is not the ProxyAdmin."}],"ProxyAdminOwnedBase_NotProxyAdminOrProxyAdminOwner()":[{"notice":"Thrown when the caller is not the ProxyAdmin owner or the ProxyAdmin."}],"ProxyAdminOwnedBase_NotProxyAdminOwner()":[{"notice":"Thrown when the caller is not the ProxyAdmin owner."}],"ProxyAdminOwnedBase_NotResolvedDelegateProxy()":[{"notice":"Thrown when the current contract is not a ResolvedDelegateProxy."}],"ProxyAdminOwnedBase_NotSharedProxyAdminOwner()":[{"notice":"Thrown when the ProxyAdmin owner of the current contract is not the same as the         ProxyAdmin owner of the other Proxy address provided."}],"ProxyAdminOwnedBase_ProxyAdminNotFound()":[{"notice":"Thrown when the ProxyAdmin owner of the current contract is not found."}],"ReinitializableBase_ZeroInitVersion()":[{"notice":"Thrown when the initialization version is zero."}]},"events":{"ETHLocked(address,uint256)":{"notice":"Emitted when ETH is locked in the lockbox by an authorized portal."},"ETHUnlocked(address,uint256)":{"notice":"Emitted when ETH is unlocked from the lockbox by an authorized portal."},"LiquidityMigrated(address,uint256)":{"notice":"Emitted when ETH liquidity is migrated from the current ETH lockbox to another."},"LiquidityReceived(address,uint256)":{"notice":"Emitted when ETH liquidity is received during an authorized lockbox migration."},"LockboxAuthorized(address)":{"notice":"Emitted when an ETH lockbox is authorized to migrate its liquidity to the current ETH lockbox."},"PortalAuthorized(address)":{"notice":"Emitted when a portal is authorized to lock and unlock ETH."}},"kind":"user","methods":{"authorizeLockbox(address)":{"notice":"Authorizes an ETH lockbox to migrate its liquidity to the current ETH lockbox. We         allow this function to be called more than once for the same lockbox. A lockbox         cannot be removed from the authorized list once added."},"authorizePortal(address)":{"notice":"Authorizes a portal to lock and unlock ETH."},"authorizedLockboxes(address)":{"notice":"Mapping of authorized lockboxes."},"authorizedPortals(address)":{"notice":"Mapping of authorized portals."},"constructor":{"notice":"Constructs the ETHLockbox contract."},"initVersion()":{"notice":"Getter for the current initialization version."},"initialize(address,address[])":{"notice":"Initializer."},"lockETH()":{"notice":"Locks ETH in the lockbox.         Called by an authorized portal on a deposit to lock the ETH value."},"migrateLiquidity(address)":{"notice":"Migrates liquidity from the current ETH lockbox to another."},"paused()":{"notice":"Getter for the current paused status."},"proxyAdmin()":{"notice":"Getter for the ProxyAdmin contract that owns this Proxy contract."},"proxyAdminOwner()":{"notice":"Getter for the owner of the ProxyAdmin."},"receiveLiquidity()":{"notice":"Receives the ETH liquidity migrated from an authorized lockbox."},"superchainConfig()":{"notice":"Returns the SuperchainConfig contract."},"systemConfig()":{"notice":"The address of the SystemConfig contract."},"unlockETH(uint256)":{"notice":"Unlocks ETH from the lockbox.         Called by an authorized portal when finalizing a withdrawal that requires ETH.         Cannot be called if the lockbox is paused."},"version()":{"notice":"Semantic version."}},"notice":"Manages ETH liquidity locking and unlocking for authorized OptimismPortals, enabling unified ETH liquidity         management across chains in the superchain cluster.","version":1}},"settings":{"compilationTarget":{"src/L1/ETHLockbox.sol":"ETHLockbox"},"evmVersion":"london","libraries":{},"metadata":{"bytecodeHash":"none","useLiteralContent":true},"optimizer":{"enabled":true,"runs":999999},"remappings":[":@lib-keccak/=lib/lib-keccak/contracts/lib/",":@openzeppelin/contracts-upgradeable/=lib/openzeppelin-contracts-upgradeable/contracts/",":@openzeppelin/contracts-v5/=lib/openzeppelin-contracts-v5/contracts/",":@openzeppelin/contracts/=lib/openzeppelin-contracts/contracts/",":@rari-capital/solmate/=lib/solmate/",":@solady-test/=lib/lib-keccak/lib/solady/test/",":@solady-v0.0.245/=lib/solady-v0.0.245/src/",":@solady/=lib/solady/src/",":ds-test/=lib/forge-std/lib/ds-test/